4077 SwitchInst::CaseIt
4078 SwitchInstProfUpdateWrapper::removeCase(SwitchInst::CaseIt I) {
4079   if (Weights) {
4080     assert(SI.getNumSuccessors() == Weights->size() &&
4081            "num of prof branch_weights must accord with num of successors");
4082     Changed = true;
4083     // Copy the last case to the place of the removed one and shrink.
4084     // This is tightly coupled with the way SwitchInst::removeCase() removes
4085     // the cases in SwitchInst::removeCase(CaseIt).
4086     (*Weights)[I->getCaseIndex() + 1] = Weights->back();
4087     Weights->pop_back();
4088   }
