9601 std::optional<bool> llvm::isImpliedCondition(const Value *LHS, const Value *RHS,
9602                                              const DataLayout &DL,
9603                                              bool LHSIsTrue, unsigned Depth) {
9604   // LHS ==> RHS by definition
9605   if (LHS == RHS)
9606     return LHSIsTrue;
9607 
9608   // Match not
9609   bool InvertRHS = false;
9610   if (match(RHS, m_Not(m_Value(RHS)))) {
9611     if (LHS == RHS)
9612       return !LHSIsTrue;
9613     InvertRHS = true;
9614   }
9615 
9616   if (const ICmpInst *RHSCmp = dyn_cast<ICmpInst>(RHS)) {
9617     if (auto Implied = isImpliedCondition(
9618             LHS, RHSCmp->getCmpPredicate(), RHSCmp->getOperand(0),
9619             RHSCmp->getOperand(1), DL, LHSIsTrue, Depth))
9620       return InvertRHS ? !*Implied : *Implied;
9621     return std::nullopt;
9622   }
9623 
9624   if (Depth == MaxAnalysisRecursionDepth)
9625     return std::nullopt;
9626 
9627   // LHS ==> (RHS1 || RHS2) if LHS ==> RHS1 or LHS ==> RHS2
9628   // LHS ==> !(RHS1 && RHS2) if LHS ==> !RHS1 or LHS ==> !RHS2
9629   const Value *RHS1, *RHS2;
9630   if (match(RHS, m_LogicalOr(m_Value(RHS1), m_Value(RHS2)))) {
9631     if (std::optional<bool> Imp =
9632             isImpliedCondition(LHS, RHS1, DL, LHSIsTrue, Depth + 1))
9633       if (*Imp == true)
9634         return !InvertRHS;
9635     if (std::optional<bool> Imp =
9636             isImpliedCondition(LHS, RHS2, DL, LHSIsTrue, Depth + 1))
9637       if (*Imp == true)
9638         return !InvertRHS;
9639   }
9640   if (match(RHS, m_LogicalAnd(m_Value(RHS1), m_Value(RHS2)))) {
9641     if (std::optional<bool> Imp =
9642             isImpliedCondition(LHS, RHS1, DL, LHSIsTrue, Depth + 1))
9643       if (*Imp == false)
9644         return InvertRHS;
9645     if (std::optional<bool> Imp =
9646             isImpliedCondition(LHS, RHS2, DL, LHSIsTrue, Depth + 1))
9647       if (*Imp == false)
9648         return InvertRHS;
9649   }
9650 
9651   return std::nullopt;
9652 }
